#include <bits/stdc++.h>
using namespace std;
const int N=20,inf=0x3f3f3f3f;
int n,m,r,c,a[N][N],dp[N][N],ans=0x3f3f3f3f;
int count(int x)
{
	int cnt=0;
	while(x)
	{
		if(x%2) cnt++;
		x/=2;
	}
	return cnt;
}
int now(int x,int y)
{
	int lst=inf,sum=0;
	for(int i=1;i<=n;i++)
	{
		if(((1<<(i-1))&x)==0) continue;
		if(lst!=inf)
		{
			sum+=abs(a[i][y]-lst);
		}
		lst=a[i][y];
//		cout<<i<<" "<<lst<<" aaa ";
	}
	return sum;
}
int fun2(int x,int y,int z)
{
	int sum=0;
	for(int i=1;i<=n;i++)
	{
		if(((1<<(i-1))&x)==0) continue;
		sum+=abs(a[i][y]-a[i][z]);
	}
	return sum;
}
int fun(int x)
{
	memset(dp,0x3f,sizeof(dp));
	int ans2=0x3f3f3f3f;
	for(int i=1;i<=m;i++)
	{
		int num=now(x,i);
		for(int j=1;j<=c;j++)
		{
			if(j==1) dp[i][j]=num;
			else
			{
				for(int k=j-1;k<i;k++)
				{
					dp[i][j]=min(dp[i][j],dp[k][j-1]+num+fun2(x,k,i));
				}
			}
//			cout<<dp[i][j]<<" ";
		}
//		cout<<"\n";
		ans2=min(ans2,dp[i][c]);
	}
	return ans2;
}
int main()
{
	cin>>n>>m>>r>>c;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++) cin>>a[i][j];
	}
	for(int i=1;i<(1<<n);i++) //hang
	{
//		for(int j=1;j<=m;j++)
//		{
//			cout<<i<<" "<<j<<"  : "<<endl;
//			cout<<now(i,j)<<"\n";
//		}
		if(count(i)!=r) continue;
//		cout<<i<<" :"<<endl;
		ans=min(ans,fun(i));
//		cout<<"\n";
	}
	cout<<ans;
	return 0;
}
